column6:
{
  "note": "You likely need substitute chili sauce options to replicate the same spicy, garlicky sriracha flavor profile.",
  "alts": [
    {
      "name_en": "Cholula Hot Sauce (Sriracha-style heat)",
      "match": "Similar",
      "desc": "A tangy, smoky chili hot sauce with a comparable kick, though it won’t be as garlicky as sriracha.",
      "where": "Hot sauce aisle / condiments (near other Mexican-style hot sauces)"
    },
    {
      "name_en": "Tabasco Chipotle Pepper Sauce",
      "match": "Similar",
      "desc": "Chipotle-forward heat adds a smoky flavor that can stand in for sriracha’s punch, but the taste profile differs.",
      "where": "Hot sauce aisle / condiments"
    },
    {
      "name_en": "Frank’s RedHot Original Cayenne Pepper Sauce",
      "match": "Similar",
      "desc": "Bright cayenne heat works well as a sriracha-like table sauce, with a thinner, more vinegar-forward flavor.",
      "where": "Hot sauce aisle / condiments (near other cayenne sauces)"
    },
    {
      "name_en": "Go-Chang Korean Gochujang (Korean chili paste) – if using as a drizzle/mix-in",
      "match": "Different but works",
      "desc": "Thick, sweet-savory Korean chili paste that can be thinned and used to deliver similar spicy depth in cooking.",
      "where": "International foods aisle (Korean condiments area, near gochujang and doenjang)"
    }
  ]
}

column12:
{
  "note": "The user is looking for sriracha alternatives available in North American stores.",
  "alts": [
    {
      "name_en": "Huy Fong Chili Garlic Sauce",
      "match": "Very close",
      "desc": "A popular, readily available sauce made from ground fresh chilies and garlic, offering a similar spicy and savory profile to sriracha but with a chunkier texture.",
      "where": "Asian foods aisle, condiments"
    },
    {
      "name_en": "Sambal Oelek",
      "match": "Similar",
      "desc": "An Indonesian chili paste made from raw ground chilis, salt, and vinegar, providing a pure, unadulterated spicy kick that is less sweet and more acidic than sriracha.",
      "where": "Asian foods aisle, condiments"
    },
    {
      "name_en": "Gochujang",
      "match": "Similar",
      "desc": "A savory, sweet, and spicy fermented Korean chili paste, offering a deeper, more complex umami flavor and thicker consistency than sriracha, with a distinctive fermented tang.",
      "where": "Asian foods aisle"
    },
    {
      "name_en": "Frank's RedHot Original Cayenne Pepper Sauce",
      "match": "Different but works",
      "desc": "A classic American hot sauce made from aged cayenne peppers, providing a vinegary, medium-spicy kick that is less sweet and garlicky than sriracha but versatile for many dishes.",
      "where": "Condiments aisle"
    }
  ]
}

