column6:
{
  "note": "Need lactose-intolerant butter alternatives that are broadly available in North American grocery stores.",
  "alts": [
    {
      "name_en": "Lactose-Free Butter",
      "match": "Very close",
      "desc": "Real butter formulated to contain little to no lactose, making it the closest option to standard butter texture and taste.",
      "where": "Dairy case (butter/butter substitutes section) near regular butter"
    },
    {
      "name_en": "Butter Substitute Spread (Lactose-Free)",
      "match": "Very close",
      "desc": "A butter-style spread made without lactose for easier tolerance while keeping a similar spreadable and cooking use.",
      "where": "Dairy case (butter alternatives / spreads section)"
    },
    {
      "name_en": "Ghee (Lactose-Free Clarified Butter)",
      "match": "Very close",
      "desc": "Clarified butter with most milk solids removed, typically lactose-free and well-suited for cooking and flavoring.",
      "where": "International/ethnic aisle or dairy/cheese section (often shelf-stable or refrigerated depending on brand)"
    },
    {
      "name_en": "Plant-Based Butter (Lactose-Free)",
      "match": "Different but works",
      "desc": "A non-dairy butter alternative (usually made from oils) that is naturally lactose-free and works for spreading and many recipes.",
      "where": "Dairy case near vegan spreads or refrigerated vegan section"
    }
  ]
}

column12:
{
