column6:
{
  "note": "Rice vinegar is needed to replace a common pantry acid used for sushi, dressings, and marinades.",
  "alts": [
    {
      "name_en": "White rice vinegar",
      "match": "Very close",
      "desc": "A direct swap for rice vinegar in mild, slightly sweet/salty recipes because it’s the same vinegar type with a different brand.",
      "where": "Aisle with Asian ingredients or vinegar/specialty condiments"
    },
    {
      "name_en": "Seasoned rice vinegar (for sushi)",
      "match": "Very close",
      "desc": "Works for sushi-style rice and similar uses since it already contains sugar and salt, though flavor will be slightly sweeter.",
      "where": "Asian foods aisle, near sushi ingredients"
    },
    {
      "name_en": "Mirin (Japanese rice cooking wine) plus a splash of water + vinegar (if needed)",
      "match": "Similar",
      "desc": "Closest flavor profile for Japanese cooking where sweetness and acidity matter, but it won’t be identical to straight rice vinegar.",
      "where": "Asian foods aisle, near Japanese sauces and cooking wines"
    },
    {
      "name_en": "Apple cider vinegar",
      "match": "Different but works",
      "desc": "An accessible vinegar substitute for dressings and marinades; acidity will match but the flavor will be fruitier and less neutral.",
      "where": "Vinegar aisle or baking supplies"
    }
  ]
}

column12:
{
  "note": "Rice vinegar is a common Asian pantry staple used in dressings, marinades, and sushi.",
  "alts": [
    {
      "name_en": "Apple Cider Vinegar",
      "match": "Similar",
      "desc": "A good all-purpose vinegar with a slightly fruity, tangy flavor that works well in dressings and marinades.",
      "where": "Condiments aisle"
    },
    {
      "name_en": "White Wine Vinegar",
      "match": "Similar",
      "desc": "Offers a bright, acidic flavor similar to rice vinegar, making it suitable for many recipes, especially vinaigrettes.",
      "where": "Condiments aisle"
    },
    {
      "name_en": "Seasoned Rice Vinegar",
      "match": "Very close",
      "desc": "This is rice vinegar with added sugar and salt, often used for sushi rice, but can be a direct substitute if you adjust for sweetness/saltiness.",
      "where": "Asian foods aisle"
    },
    {
      "name_en": "Mirin (Sweet Rice Wine)",
      "match": "Different but works",
      "desc": "While sweeter and less acidic, it's a traditional Japanese ingredient that can substitute in some marinades and sauces for a similar umami depth. Use less or balance with a touch of other vinegar.",
      "where": "Asian foods aisle"
    }
