}

column18:
{
  "note": "Rice vinegar is a staple in Asian cooking with a mild, slightly sweet profile that's hard to replicate exactly.",
  "alts": [
    {
      "name_en": "White vinegar",
      "match": "Similar",
      "desc": "Sharper and more acidic than rice vinegar, but works as a 1:1 substitute in most recipes when diluted slightly with water.",
      "where": "Condiment aisle"
    },
    {
      "name_en": "Apple cider vinegar",
      "match": "Similar",
      "desc": "Milder and slightly sweeter than white vinegar with a fruity undertone; use at 0.75:1 ratio to avoid overpowering dishes.",
      "where": "Condiment or health foods aisle"
    },
    {
      "name_en": "Champagne vinegar",
      "match": "Similar",
      "desc": "Delicate and slightly sweet with lower acidity, closely mimics rice vinegar's subtle flavor profile.",
      "where": "Specialty or gourmet foods section"
    },
    {
      "name_en": "Distilled white vinegar + sugar",
      "match": "Different but works",
      "desc": "Mix white vinegar with a pinch of sugar to approximate rice vinegar's sweetness and balance.",
      "where": "Condiment aisle (combine ingredients)"
    }
  ]
}

column6:
{
  "note": "You need vegetarian substitutes for chicken breast that can replace it in recipes with a similar protein role.",
  "alts": [
    {
      "name_en": "Tofu (extra-firm) ",
      "match": "Different but works",
      "desc": "Extra-firm tofu has a meaty bite and absorbs marinades well, making it a reliable stand-in for grilled or pan-seared chicken breast.",
      "where": "Produce/Meals area near refrigerated tofu in the grocery store (often in the refrigerated section by plant-based foods)."
    },
    {
      "name_en": "Seitan (wheat gluten)",
      "match": "Different but works",
      "desc": "Seitan is high-protein and chewier, working well for stir-fries, cutlets, or shredded ‘chicken’ style dishes.",
      "where": "Refrigerated plant-based or international foods section (often near tofu/tempeh alternatives)."
    },
    {
      "name_en": "Plant-based chicken (frozen or refrigerated—e.g., soy or pea-protein cutlets)",
      "match": "Different but works",
      "desc": "These products are designed to mimic chicken texture and flavor, making them a direct swap in most recipes.",
      "where": "Frozen section (plant-based meat) or refrigerated section near other meat alternatives."
    },
    {
      "name_en": "Tempeh",
      "match": "Different but works",
      "desc": "Tempeh offers a firm, protein-rich texture and nutty flavor that holds up to grilling, roasting, or slicing like chicken.",
      "where": "Refrigerated section near tofu and other cultured soy/plant proteins."
    }
  ]
}

