column6:
{
  "note": "Provide Korean-friendly substitutes to replace fish sauce in North American grocery shopping options.",
  "alts": [
    {
      "name_en": "Oyster Sauce",
      "match": "Similar",
      "desc": "Salty umami sauce that can mimic the savory depth in Korean cooking (though less fishy and typically slightly sweeter).",
      "where": "Asian aisle or condiment/sauce section (often near Korean/Chinese sauces)."
    },
    {
      "name_en": "Soy Sauce + a pinch of sugar",
      "match": "Different but works",
      "desc": "Korean recipes often use soy sauce for briny umami, and a small amount of sugar can help replace fish sauce’s rounding effect.",
      "where": "Condiment aisle (soy sauce shelf)."
    },
    {
      "name_en": "Gochujang (Korean chili paste)",
      "match": "Different but works",
      "desc": "Not a direct swap, but its fermented umami and saltiness can provide similar depth for marinades and stews in Korean-style cooking.",
      "where": "Korean section of the Asian aisle (gochujang/jang category)."
    },
    {
      "name_en": "Anchovy paste",
      "match": "Similar",
      "desc": "A concentrated anchovy-based option that is much closer in flavor profile to fish sauce than other pantry sauces.",
      "where": "Gourmet/condiments aisle or canned/jarred seafood section; sometimes near anchovies or Caesar salad ingredients."
    }
  ]
}

column12:
{
  "note": "The user enjoys Korean cuisine and needs alternatives for fish sauce.",
  "alts": [
    {
      "name_en": "Katsuobushi (Bonito Flakes) Dashi",
      "match": "Similar",
      "desc": "This Japanese broth made from dried, smoked skipjack tuna provides a deep umami and savory flavor profile, similar to fish sauce but with a smokier nuance often used in Korean cooking.",
      "where": "International aisle (Asian section), often near ramen or dried seaweed"
    },
    {
      "name_en": "Soy Sauce (Ganjang)",
      "match": "Different but works",
      "desc": "A fundamental Korean condiment, soy sauce offers a rich, salty, and umami base, though it lacks the distinct fermented fish aroma and flavor of fish sauce.",
      "where": "International aisle (Asian section) or condiments"
    },
    {
      "name_en": "Doenjang (Korean Fermented Soybean Paste)",
      "match": "Different but works",
      "desc": "This savory, earthy, and umami-rich fermented soybean paste is a staple in Korean cuisine and can contribute a deep, complex flavor to dishes, albeit with a different profile than fish sauce.",
      "where": "International aisle (Korean section) or refrigerated Asian foods"
    },
    {
      "name_en": "Anchovy Extract (Myeolchi Aekjeot)",
      "match": "Very close",
      "desc": "This Korean-specific anchovy extract is essentially a direct Korean equivalent to Southeast Asian fish sauce, offering the same pungent, salty, and umami-rich flavor profile.",
      "where": "International aisle (Korean section) or refrigerated Asian foods"
    }
  ]
}

